(17, 12, '1743990128_1. 1BR Pool Villa .png', '1BR Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Refreshing welcome drink and cold towel upon arrival.</li><li>Welcome fruit basket and flower arrangement upon arrival. </li><li>Daily breakfast for 2 people per room in your private villa or at Mase Kitchen &amp; Wine \r\nBar</li><li>Daily afternoon tea at Mase Kitchen &amp; Wine Bar </li><li>Mineral water during stay</li><li>In villa check in and checkout process </li><li>Wi-Fi internet connection through-out the resort.</li><li>Personal in villa check in</li><li>Butler service</li><li>Complimentary shuttled service within and Seminyak area based on scheduled</li><li>Daily turn down service</li><li>Free access to our modern &amp; Hi Tec Fitness Center, join regular multiclass and yoga \r\nsession as well as use the steam, sauna, hot &amp; cold plunge pool at Soham Wellness \r\nCenter&nbsp;</li></ul>', 'Size: 110 sqm&nbsp;', 'Active', '2022-11-05 20:54:59', '2025-04-07 01:42:27'),
(18, 12, '1743990199_2. 1BR Deluxe Pool Villa .png', '1BR Deluxe Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Refreshing welcome drink and cold towel upon arrival.</li><li>Welcome fruit basket and flower arrangement upon arrival.</li><li>Daily breakfast for 2 people per room in your private villa or at Mase Kitchen &amp; Wine Bar</li><li>Daily afternoon tea at Mase Kitchen &amp; Wine Bar</li><li>Mineral water during stay</li><li>In villa check in and checkout process</li><li>Wi-Fi internet connection through-out the resort.</li><li>Personal in villa check in</li><li>Butler service</li><li>Complimentary shuttled service within and Seminyak area based on scheduled</li><li>Daily turn down service</li><li>Free access to our modern &amp; Hi Tec Fitness Center, join regular multiclass and yoga session as well as use the steam, sauna, hot &amp; cold plunge pool at Soham Wellness Center&nbsp;</li></ul>', 'Size: 140 sqm&nbsp;', 'Active', '2022-11-05 20:55:35', '2025-04-07 01:43:19'),
(19, 12, '1743990279_3. 2BR Deluxe Pool Villa .png', '2BR Deluxe Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Refreshing welcome drink and cold towel upon arrival.</li><li>Welcome fruit basket and flower arrangement upon arrival.</li><li>Daily breakfast for 2 people per room in your private villa or at Mase Kitchen &amp; Wine Bar</li><li>Daily afternoon tea at Mase Kitchen &amp; Wine Bar</li><li>Mineral water during stay</li><li>In villa check in and checkout process</li><li>Wi-Fi internet connection through-out the resort.</li><li>Personal in villa check in</li><li>Butler service</li><li>Complimentary shuttled service within and Seminyak area based on scheduled</li><li>Daily turn down service</li><li>Free access to our modern &amp; Hi Tec Fitness Center, join regular multiclass and yoga session as well as use the steam, sauna, hot &amp; cold plunge pool at Soham Wellness Center&nbsp;</li></ul>', 'Size: 220 sqm&nbsp;', 'Active', '2022-11-05 20:56:18', '2025-04-07 01:44:39'),
(22, 13, '1743665535_1. Hill Side Villa.jpg', 'Hill Side Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily breakfast served in the villa or a la carte menu served at Scene restaurant&nbsp;</li><li>Welcome drink and cold towel upon arrival&nbsp;</li><li>Samaya creative welcome&nbsp;</li><li>Complimentary shuttle service within local area subject to hotel car availability&nbsp;</li><li>Free W-Fi internet connection 100% of the property&nbsp;</li><li>Daily afternoon tea from 3 : 00 pm to 5 :00 pm in the villa or at Scene restaurant&nbsp;</li><li>Yoga class 3 times a week based on hotel’s schedule&nbsp;</li><li>Morning Cycling and green &amp; culture trekking based on hotel’s schedule&nbsp;</li><li>24/7 butler service and daily turn down services&nbsp;</li></ul>', '<ul><li>Size: 392 sqm&nbsp;</li><li>Maximum Capacity: 2A + 1C + 1 Infant or 3A&nbsp;(with additional&nbsp;extra bed)&nbsp;</li></ul>', 'Active', '2022-11-05 21:58:18', '2025-07-29 07:25:06'),
