(169, 18, '1697440963_Garden Villa with Private Pool.webp', 'Garden Villa with Private Pool', 2, 1, 'Garden View', 'King Bed', 210, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink upon arrival&nbsp;</li><li>Daily breakfast for 2 adults&nbsp;</li><li>24 hour E-Butler Service&nbsp;</li><li>Evening turn-down service with canape bites&nbsp;</li><li>Capsule coffee making facilities and premium selected teas&nbsp;</li><li>Direct access to beach&nbsp;</li></ul><p>Bellow additional inclusion are not valid for Peak Season (20 Dec 2024 - 05 Jan 2025)&nbsp;</p><ul><li>2 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons&nbsp;</li><li>3 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons &amp; One time 60 minutes Balinese Massage at Talise Spa for 2 persons&nbsp;</li><li>4 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons &amp; One time 60 minutes Balinese Massage at Talise Spa for 2 persons &amp; One time Afternoon Tea at maja Lounge for 2 persons</li></ul>', NULL, 'Draft', '2022-11-16 20:59:36', '2026-02-02 01:23:35'),
