(232, 54, '1669612788_Suite Room.webp', 'Suite Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Complimentary welcome drink</li><li>Daily breakfast</li><li>Daily afternoon tea</li><li>Daily seasonal fruit basket</li><li>Daily 2 bottles mineral water</li><li>Free Wifi &ndash; All Hotel&rsquo;s area</li><li>Free Daily Guest activities based on schedule</li><li>Honeymoon benefits available based on request (flower decoration on the bed &amp; cake)&nbsp;</li></ul>', '<p>Size: 50m2</p>', 'Active', '2022-11-26 18:19:48', '2024-11-11 04:00:18'),
(233, 55, '1669619663_Terrace Tent.webp', 'Terrace Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul>', '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult/1 child/1 infant or 3 adult&nbsp;</p><p>Offering a rice terrace or forest outlook and a private saltwater pool.&nbsp;</p>', 'Draft', '2022-11-26 20:14:24', '2025-04-02 01:03:00'),
(234, 55, '1669619698_Rainforest Tent.webp', 'Rainforest Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul><p>&nbsp;</p>', '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult/1 child/1 infant or 3 adult&nbsp;</p><p>Offering a rainforest setting and view with a private saltwater pool.&nbsp;</p>', 'Draft', '2022-11-26 20:14:58', '2025-04-02 01:03:00'),
(235, 55, '1669620046_River Tent.webp', 'River Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul>', '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult or 3 adult&nbsp;</p><p>Offering a Wos river experience and view with a private saltwater pool</p><p>NB: No infants and children below the age of 10 yo</p>', 'Draft', '2022-11-26 20:20:46', '2025-04-02 01:03:00'),
(236, 55, '1669620185_Keliki Valley.webp', 'Keliki Valley Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul>', '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult or 3 adult&nbsp;</p><p>Offering unobstructed elevated Keliki Valley views and a private saltwater pool.&nbsp;</p><p>NB: No infants and children below the age of 10 yo</p>', 'Draft', '2022-11-26 20:23:06', '2025-04-02 01:03:00'),
