(244, 57, '1669689786_Garden Villa.webp', 'Garden Villa', 2, 1, 'Garden View', 'King Size or Twin Beds', 150, '<ol><li>Air-conditioning</li><li>Mini bar</li><li>Bathtub with hot and cold shower</li><li>King-size or Twin bed</li><li>Private veranda</li><li>Reusable shopping bag</li><li>In-room safety deposit box</li><li>WiFi connection</li><li>Yoga mat</li></ol>', '<p>空調<br data-start=\"444\" data-end=\"447\">\r\n迷你吧<br data-start=\"452\" data-end=\"455\">\r\n附有冷熱水淋浴的浴缸<br data-start=\"467\" data-end=\"470\">\r\n特大床或雙床<br data-start=\"478\" data-end=\"481\">\r\n私人陽台<br data-start=\"487\" data-end=\"490\">\r\n可重複使用的購物袋<br data-start=\"501\" data-end=\"504\">\r\n客房保險箱<br data-start=\"511\" data-end=\"514\">\r\n無線網路連線<br data-start=\"522\" data-end=\"525\">\r\n瑜伽墊</p>', '<ul><li>空调<br data-start=\"317\" data-end=\"320\">\r\n迷你吧<br data-start=\"325\" data-end=\"328\">\r\n带冷热水淋浴的浴缸<br data-start=\"339\" data-end=\"342\">\r\n特大床或双床<br data-start=\"350\" data-end=\"353\">\r\n私人阳台<br data-start=\"359\" data-end=\"362\">\r\n可重复使用的购物袋<br data-start=\"373\" data-end=\"376\">\r\n客房保险箱<br data-start=\"383\" data-end=\"386\">\r\n无线网络连接<br data-start=\"394\" data-end=\"397\">\r\n瑜伽垫</li></ul>', NULL, NULL, '<ul><li>Daily breakfast&nbsp;</li><li>1 jar of cookies &nbsp;</li><li>Daily afternoon tea with Balinese and Western finger foods</li><li>Daily yoga</li><li>Daily activities (cultural or seasonal)</li><li>Shuttle for Ubud properties: around Ubud center. For Keramas: around Keramas area&nbsp;</li></ul>', NULL, 'Active', '2022-11-27 15:43:09', '2025-10-27 07:11:32'),
