(301, 69, '1669777125_1BR Club Pool Villa.webp', '1BR Club Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p><strong>Club Benefits:&nbsp;</strong></p><ul><li>Welcome drink upon arrival</li><li>Team Butler service</li><li>Daily a la carte breakfast in Suite/ Villa or at The Tempayan Restaurant</li><li>Daily seasonal fresh fruits delivered to your villa or suite</li><li>Car service to/ from Ubud Centre with private car during the day</li><li>Wi-Fi access in the villa or suite and public areas</li><li>Daily afternoon tea 16:00 &ndash; 18:00 served at Panen Padi Lounge</li><li>Daily sunset cocktails 18:00 &ndash; 19:00 served at Tempayan Terrace</li><li>Complimentary replenished mini bar (beer, juices, soft drink, mineral water and milk) and snacks including alcoholic (Gin,Vodka,Whiskey)</li><li>Complimentary laundry service up to six pieces per room OR 12 pcs for two bedroom (excluding dry cleaning)</li><li>Complimentary 1x trekking activity with dedicated butler</li><li>Daily scheduled Yoga classes 7:30 am &ndash; 9 am</li><li>Complimentary used of Gymnasium and Tennis Court</li><li>Gym operation start from 7 am &ndash; 9 pm</li><li>Tennis court operations start from 7 am &ndash; 6 pm</li></ul><p><strong>Minimum stay benefit:&nbsp;</strong></p><ul><li>2 Nights will get 1x complimentary 60 minutes Balinese Massage for two&nbsp;</li><li>3 Nights will get 1x complimentary 90 minutes Balinese Massage for two&nbsp;</li><li>4 Nights will get 3 nights benefit AND one time 3 Course Dinner&nbsp;</li></ul>', '<p>Honeymoon and Wedding Anniversary Benefits: Honeymoon guests in any room category, will receive the following benefits:</p><ul><li>1x Honeymoon Cake on turndown on the night of day of arrival</li><li>1x Honeymoon Flower arrangement in room</li><li>1x Special Aromatherapy floral bath on the first night of the day of arrival</li></ul>', 'Active', '2022-11-28 15:58:45', '2024-12-10 07:03:27'),
(302, 69, '1669777191_2BR Club Family Pool Villa.webp', '2BR Club Family Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<b>Club Benefits:&nbsp;</b><ul><li>Welcome drink upon arrival</li><li>Team Butler service</li><li>Daily a la carte breakfast in Suite/ Villa or at The Tempayan Restaurant</li><li>Daily seasonal fresh fruits delivered to your villa or suite</li><li>Car service to/ from Ubud Centre with private car during the day</li><li>Wi-Fi access in the villa or suite and public areas</li><li>Daily afternoon tea 16:00 – 18:00 served at Panen Padi Lounge</li><li>Daily sunset cocktails 18:00 – 19:00 served at Tempayan Terrace</li><li>Complimentary replenished mini bar (beer, juices, soft drink, mineral water and milk) and snacks including alcoholic (Gin,Vodka,Whiskey)</li><li>Complimentary laundry service up to six pieces per room OR 12 pcs for two bedroom (excluding dry cleaning)</li><li>Complimentary 1x trekking activity with dedicated butler</li><li>Daily scheduled Yoga classes 7:30 am – 9 am</li><li>Complimentary used of Gymnasium and Tennis Court</li><li>Gym operation start from 7 am – 9 pm</li><li>Tennis court operations start from 7 am – 6 pm</li></ul><b>Minimum stay benefit:&nbsp;</b><ul><li>2 Nights will get 1x complimentary 60 minutes Balinese Massage for two&nbsp;</li><li>3 Nights will get 1x complimentary 90 minutes Balinese Massage for two&nbsp;</li><li>4 Nights will get 3 nights benefit AND one time 3 Course Dinner&nbsp;</li></ul>', '<b>Honeymoon and Wedding Anniversary Benefits:</b> <br>Honeymoon guests in any room category, will receive the following benefits:<ul><li>1x Honeymoon Cake on turndown on the night of day of arrival</li><li>1x Honeymoon Flower arrangement in room</li><li>1x Special Aromatherapy floral bath on the first night of the day of arrival</li></ul>', 'Active', '2022-11-28 15:59:51', '2025-05-14 06:57:27'),
