(447, 93, '1748588757_3..jpg', '3BR Luxury Pool Villa Garden View', 6, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drinks upon arrival.&nbsp;</li><li>Daily Breakfast served at Akar Restaurant from 07.00 - 11.00.&nbsp;</li><li>Water Dispenser with gallon.&nbsp;</li><li>Complimentary Coffee and Tea-making facilities in the villa.&nbsp;</li><li>Morning Walk Relaxation through scenic rice fields, led by the concierge team (scheduled).&nbsp;</li><li>Sunrise Yoga Sessions are based on the schedule (reservation required).&nbsp;</li><li>Access to Gym Facilities and Kabana Jungle Pool Club.&nbsp;</li><li>Shuttle Service to and from Ubud Centre.&nbsp;</li><li>24-Hour Butler Service</li></ul>', '<ul><li>Occupancy: 6 adults &amp; 1 child&nbsp;</li><li>Room Size: 400 sqm&nbsp;</li></ul>', 'Active', '2022-12-03 16:22:00', '2025-05-30 07:05:57'),
(448, 94, '1670379212_Deluxe Room.webp', 'Deluxe Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Complimentary welcome drink</li><li>Daily breakfast</li><li>One-time&nbsp;afternoon tea per stay</li><li>One-time welcome fruit upon arrival</li><li>Daily set up mineral water&nbsp;</li><li>Complimentary daily replenish Non-Alcohol Mini Bar&nbsp;</li></ul><b>Complimentary resort guest activties following regular hotel schedule such as:</b>&nbsp;<br><ul><li>Making herbal drink and body scrub available every day at Dala Spa&nbsp;</li><li>Yoga Class available every Wednesday and Saturday start from 16:00pm - 17:00pm&nbsp;</li></ul><b>Note:&nbsp;</b><br><ul><li>Please inform to our Front Office team one day in advance to join those above class.&nbsp;</li><li>Should the guest wish to arrange private session (out of regular hotel schedule) for yoga class, separate yoga class fee is available upon request.&nbsp;&nbsp;</li></ul><b>Added Value Benefit:&nbsp;</b><br><ul><li>Minimum 2 nights stay get 1 x 60 minutes Balinese Massage OR 3 course Set Menu Lunch for 2 persons&nbsp;</li><li>Minimum 4 nights stay get 1 x 60 minutes Balinese Massage AND 3 course Set Menu Lunch for 2 persons&nbsp;</li></ul>', '<i>Extra bed is not recommended due to space constraint however if guest insist it will be set up in front of the wardrobe area with additional charge</i>', 'Active', '2022-12-05 15:13:32', '2025-05-15 02:37:33');
