(462, 18, '1697441589_Premier Garden Villa with Private Pool.webp', 'Premier Garder Villa with Private Pool', 2, 1, 'Garden View', 'King/Twin', 210, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink upon arrival&nbsp;</li><li>Daily breakfast for 2 adults&nbsp;</li><li>24 hour E-Butler Service&nbsp;</li><li>Evening turn-down service with canape bites&nbsp;</li><li>Capsule coffee making facilities and premium selected teas&nbsp;</li><li>Direct access to beach&nbsp;</li></ul><p>Bellow additional inclusion are not valid for Peak Season (20 Dec 2024 - 05 Jan 2025)&nbsp;</p><ul><li>2 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons&nbsp;</li><li>3 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons &amp; One time 60 minutes Balinese Massage at Talise Spa for 2 persons&nbsp;</li><li>4 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons &amp; One time 60 minutes Balinese Massage at Talise Spa for 2 persons &amp; One time Afternoon Tea at maja Lounge for 2 persons</li></ul>', NULL, 'Draft', '2023-03-28 19:26:57', '2026-02-02 01:23:35'),
(472, 98, '1769757257_1.webp', 'Spearmint-One Bedroom Villa', 2, 1, 'Pool View', 'King/Twin', 180, '<ol><li>Welcome drink on arrival</li><li>Daily breakfast at Sattvic Restaurant&nbsp;</li><li>Daily mineral water of two&nbsp;</li><li>Free WIFI Internet Access across the Villa </li><li>Free access to resort gym facilities and main pool </li><li>Free shuttle to Jimbaran beach based on schedule (drop off &amp; pick up)</li></ol>', '<li data-start=\"143\" data-end=\"156\"><p data-start=\"145\" data-end=\"156\">抵達時提供迎賓飲品</p>\r\n</li><li data-start=\"157\" data-end=\"179\">\r\n<p data-start=\"159\" data-end=\"179\">於 Sattvic 餐廳享用每日早餐</p>\r\n</li><li data-start=\"180\" data-end=\"193\">\r\n<p data-start=\"182\" data-end=\"193\">每日提供兩瓶礦泉水</p>\r\n</li><li data-start=\"194\" data-end=\"216\">\r\n<p data-start=\"196\" data-end=\"216\">別墅全區域提供免費 Wi-Fi 網路</p>\r\n</li><li data-start=\"217\" data-end=\"237\">\r\n<p data-start=\"219\" data-end=\"237\">免費使用度假村健身房設施及主泳池</p>\r\n</li><p>\r\n\r\n\r\n\r\n\r\n</p><li data-start=\"238\" data-end=\"268\">\r\n<p data-start=\"240\" data-end=\"268\">依時刻表提供往返金巴蘭海灘的免費接駁服務（接送服務）</p></li>', '<li data-start=\"308\" data-end=\"321\"><p data-start=\"310\" data-end=\"321\">抵达时提供欢迎饮品</p>\r\n</li><li data-start=\"322\" data-end=\"344\">\r\n<p data-start=\"324\" data-end=\"344\">于 Sattvic 餐厅享用每日早餐</p>\r\n</li><li data-start=\"345\" data-end=\"358\">\r\n<p data-start=\"347\" data-end=\"358\">每日提供两瓶矿泉水</p>\r\n</li><li data-start=\"359\" data-end=\"381\">\r\n<p data-start=\"361\" data-end=\"381\">别墅全区域提供免费 Wi-Fi 网络</p>\r\n</li><li data-start=\"382\" data-end=\"402\">\r\n<p data-start=\"384\" data-end=\"402\">免费使用度假村健身房设施及主泳池</p>\r\n</li><p>\r\n\r\n\r\n\r\n\r\n</p><li data-start=\"403\" data-end=\"432\">\r\n<p data-start=\"405\" data-end=\"432\">根据时间表提供往返金巴兰海滩的免费接驳服务（接送）</p></li>', NULL, NULL, '<ul><li>Daily breakfast&nbsp;</li><li>Welcome drink upon arrival&nbsp;</li><li>Wi-Fi in the room and throughout resort area&nbsp;</li></ul>', NULL, 'Active', '2023-05