(533, 63, '1688982715_1BR Garden Pool Villa.webp', '1BR Garden Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink &amp; Cold towel upon check-in</li><li>Fresh Fruit amenities in your room (Arrival day)</li><li>Daily buffet breakfast in Rempah-rempah Restaurant or in your own private suites or villas or you may pamper yourself by having Floating Breakfast which can be served in your private pool while gazing to the Indian Ocean</li><li>Daily free-flow non alcoholic beverages at any of the open restaurants and bars</li><li>Complimentary one time daily replenished mini bar, stocked with beer and soft drinks</li><li>Daily afternoon tea at any of the open restaurnats or in your own suites or villas from 14.30 to 17.00 hours</li><li>Daily turn down service</li><li>Daily complimentary yoga at the beach side (Except Sunday)</li><li>Daily fruit service at the pool side (15.00 hours)</li><li>Daily ice cream service for children at the pool side (15.00 hours)</li><li>Daily cooling cucumber eye compress at the pool side (15.00 hours)</li><li>Gym, cooking class and other guest activities included</li><li>Complimentary wireless internet access in your room and resort area</li><li>Samabe original welcome gift for each guest &amp; 24 hours butler service</li><li>Complimentary use of non-motorized water sports (catamaran/kayak/windsurfer, snorkeling , stand up - paddle)</li><li>Hospitality lounge for early check-in or late check-out</li></ul>', '<ul><li>Paid Occupancy: 2 Guest&nbsp;</li><li>Occupancy: 3&nbsp;adults or&nbsp;2 adults + 2 child&nbsp;</li><li>Max 1&nbsp;extra bed possible&nbsp;</li><li>Children below 3 years old using existing bedding stay free of charge&nbsp;</li></ul>', 'Active', '2023-07-10 10:51:55', '2024-02-29 03:47:27'),
(534, 63, '1688983416_2BR Garden Pool Villa.webp', '2BR Garden Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink &amp; Cold towel upon check-in</li><li>Fresh Fruit amenities in your room (Arrival day)</li><li>Daily buffet breakfast in Rempah-rempah Restaurant or in your own private suites or villas or you may pamper yourself by having Floating Breakfast which can be served in your private pool while gazing to the Indian Ocean</li><li>Daily free-flow non alcoholic beverages at any of the open restaurants and bars</li><li>Complimentary one time daily replenished mini bar, stocked with beer and soft drinks</li><li>Daily afternoon tea at any of the open restaurnats or in your own suites or villas from 14.30 to 17.00 hours</li><li>Daily turn down service</li><li>Daily complimentary yoga at the beach side (Except Sunday)</li><li>Daily fruit service at the pool side (15.00 hours)</li><li>Daily ice cream service for children at the pool side (15.00 hours)</li><li>Daily cooling cucumber eye compress at the pool side (15.00 hours)</li><li>Gym, cooking class and other guest activities included</li><li>Complimentary wireless internet access in your room and resort area</li><li>Samabe original welcome gift for each guest &amp; 24 hours butler service</li><li>Complimentary use of non-motorized water sports (catamaran/kayak/windsurfer, snorkeling , stand up - paddle)</li><li>Hospitality lounge for early check-in or late check-out</li></ul>', '<ul><li>Paid Occupancy: 4 Guest</li><li>Occupancy: 5 adults or 4&nbsp;adults + 2 child</li><li>Max 1&nbsp;extra bed possible&nbsp;</li><li>Children below 3 years old using existing bedding stay free of charge&nbsp;</li></ul>', 'Active', '2023-07-10 11:03:36', '2025-05-14 06:36:39'),
