(600, 17, '1743996538_5. 4BR Estate .png', '4BR Estate', 8, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Refreshing welcome drink and cold towel upon arrival.&nbsp;</li><li>Welcome fruit basket and flower arrangement upon arrival.&nbsp;</li><li>Daily breakfast for 2 people per room in your private villa or at Mase Uma Kitchen &amp; Bar&nbsp;</li><li>Mineral water during stay&nbsp;</li><li>In villa check in and checkout process&nbsp;</li><li>Wi-Fi internet connection through-out the resort.&nbsp;</li><li>Personal in villa check in and Butler service&nbsp;</li><li>Complimentary shuttled service within Kerobokan and Seminyak area based on scheduled&nbsp;</li><li>Daily turn down service&nbsp;</li><li>Free access to our modern &amp; Hi Tec Fitness Center, join regular multiclass and yoga session as well as use the steam, sauna, hot &amp; cold plunge pool at Soham Wellness Center</li></ul>', 'Size: 345 m2', 'Active', '2023-12-13 10:54:18', '2025-04-25 07:36:19'),
(604, 105, '1702978692_Mulia - Signature.webp', 'Signature', 2, 1, 'Garden View', 'King/Twin', 59, NULL, NULL, NULL, NULL, NULL, '<ul><li>Breakfast venue for Mulia Resort guests in all room categories are only served at the&nbsp;Café (buffet).&nbsp;</li><li>Welcome drink and sanitized wet tissue upon arrival&nbsp;</li><li>Tropical fruits upon arrival&nbsp;</li><li>Complimentary tea &amp; coffee making facility&nbsp;</li><li>Complimentary use of fitness centre&nbsp;</li><li>Complimentary access to ZJ\'s Bar, except during special event&nbsp;</li><li>Complimentary array of sport and leisure selected activties (details to be forwarded separately)&nbsp;</li><li>Complimentary use of Mulia Kidz facility during normal operating hours. All special events to be charged separately&nbsp;</li><li>Complimentary internet access in public areas and inside guest\'s room for all room categories for the whole properties (subject to enrollment of Mulia Privilege (MP) Loyalty Program)&nbsp;</li></ul>', NULL, 'Active', '2023-12-19 10:38:12', '2025-12-15 07:19:37'),
(605, 105, '1702978729_Mulia - Royal Suite.webp', 'Royal Suite', 2, 1, 'Garden view, courtyard view, beachfront view, or direct lagoon pool access', 'King/Twin', 83, NULL, NULL, NULL, NULL, NULL, '<ul><li>Breakfast venue for Mulia Resort guests in all room categories are only served at the&nbsp;Caf&eacute; (buffet).&nbsp;</li><li>Welcome drink and sanitized wet tissue upon arrival&nbsp;</li><li>Tropical fruits upon arrival&nbsp;</li><li>Complimentary tea &amp; coffee making facility&nbsp;</li><li>Complimentary use of fitness centre&nbsp;</li><li>Complimentary access to ZJ&#39;s Bar, except during special event&nbsp;</li><li>Complimentary array of sport and leisure selected activties (details to be forwarded separately)&nbsp;</li><li>Complimentary use of Mulia Kidz facility during normal operating hours. All special events to be charged separately&nbsp;</li><li>Complimentary internet access in public areas and inside guest&#39;s room for all room categories for the whole properties (subject to enrollment of Mulia Privilege (MP) Loyalty Program)&nbsp;</li></ul>', NULL, 'Active', '2023-12-19 10:38:49', '2025-12-15 08:53:37'),
