(608, 66, '1754032641_4. Tembo 3 bedroom .png', 'Tembo Family Suite', 6, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Cool towel and welcome drink on arrival</li><li>Tropical fruit in the room</li><li>Daily breakfast at Tsavo Lion Restaurant</li><li>Free entrance to Bali Safari Park&nbsp;</li><li>Animal, Tiger, and Elephant presentation (scheduled show times, subject on weather condition and changes in order to maintain an appropriate CHSE [Cleanliness, Health, Safety, Environmental Sustainability] protocol)&nbsp;</li><li>Access to Water Play Zone&nbsp;</li><li>Safari Journey (1x)</li></ul>', NULL, 'Active', '2023-12-28 05:12:21', '2025-08-01 09:43:39'),
