(632, 116, '1707706050_new.webp', '1BR Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Personalised in-villa check in.</li><li>Welcome drink, sweet lights and chilled towel upon arrival.</li><li>Daily a la carte breakfast.</li><li>Welcome fruits basket upon arrival, served in the villa.</li><li>Complimentary mineral waters, replenish daily in the villa.</li><li>Complimentary WiFi internet access in the villa and throughout the resort area.</li><li>24 hours butler services&nbsp;</li></ul><p><strong>EXTRA BENEFIT FOR HONEYMOONERS:</strong></p><ul><li>Honeymoon set up with flower petals in the bathtub and a cake in the villa upon arrival.</li><li>1 x 60 minutes Balinese massage for 2&nbsp;</li></ul>', '<p>(2 Adult + 1 Child) - King Size Bed&nbsp;</p>', 'Draft', '2024-02-12 03:45:16', '2025-04-02 01:03:03'),
