(686, 5, '1715566051_2BR Suite.webp', '2BR Suite', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Packing &amp; un-Packing Service&nbsp;</li><li>Welcome amenities fruits &amp; chocolate upon arrival&nbsp;</li><li>Additional benefit where the guests will enjoy the following:&nbsp;</li></ul><ol><li>Daily buffet / ala carte breakfast at HOMAYA from 07.00 - 10.30&nbsp;</li><li>Afternoon Tea with sweet, cookies, savory at BAR LOUNGE from 15.00 - 16.30&nbsp;</li><li>Evening free flow cocktails and canapes at BAR LOUNGE from 17.00 - 18.30. Include 2 type of drink per person. Maximum 2 persons. Drink selection are soft drink, beer, house wine and alcoholic or non-alcoholic cocktail&nbsp;</li></ol>', '<p>Size: 135 sqm&nbsp;</p><p>Max Occupants:&nbsp;</p><ul><li>4 adult&nbsp;</li><li>3 child below 12 years old (2 children with extra bed &amp; 1 child sharing bed with parents)&nbsp;</li><li>1 infant with baby cot&nbsp;</li></ul>', 'Draft', '2024-05-13 03:07:31', '2025-04-02 01:02:57'),
(687, 5, '1715566551_One-Bedroom-Villa-Bedroom.webp', '1BR Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Packing &amp; un-Packing Service&nbsp;</li><li>Welcome amenities fruits &amp; chocolate upon arrival&nbsp;</li><li>Additional benefit where the guests will enjoy the following:&nbsp;</li></ul><ol><li>Daily buffet / ala carte breakfast at HOMAYA from 07.00 - 10.30&nbsp;</li><li>Afternoon Tea with sweet, cookies, savory at BAR LOUNGE from 15.00 - 16.30&nbsp;</li><li>Evening free flow cocktails and canapes at BAR LOUNGE from 17.00 - 18.30. Include 2 type of drink per person. Maximum 2 persons. Drink selection are soft drink, beer, house wine and alcoholic or non-alcoholic cocktail&nbsp;</li></ol>', '<p>Size: 157 sqm&nbsp;</p><p>Max Occupants:&nbsp;</p><ul><li>3 adult (With existing bed + 1 extra bed)&nbsp;</li><li>1 infant with Baby cot&nbsp;</li></ul><p>Note: Children below 12 years old <strong>are not recommended</strong> to stay at <strong>1BR Pool Villa &amp; 2BR Pool Villa&nbsp;</strong></p>', 'Draft', '2024-05-13 03:15:52', '2025-04-02 01:02:57'),
(688, 5, '1715566819_Two-BedRoom-Villa-Bedroom-.webp', '2BR Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Packing &amp; un-Packing Service&nbsp;</li><li>Welcome amenities fruits &amp; chocolate upon arrival&nbsp;</li><li>Additional benefit where the guests will enjoy the following:&nbsp;</li></ul><ol><li>Daily buffet / ala carte breakfast at HOMAYA from 07.00 - 10.30&nbsp;</li><li>Afternoon Tea with sweet, cookies, savory at BAR LOUNGE from 15.00 - 16.30&nbsp;</li><li>Evening free flow cocktails and canapes at BAR LOUNGE from 17.00 - 18.30. Include 2 type of drink per person. Maximum 2 persons. Drink selection are soft drink, beer, house wine and alcoholic or non-alcoholic cocktail&nbsp;</li></ol>', '<p>Size: 300 sqm&nbsp;</p><p>Max Occupants:&nbsp;</p><ul><li>5 adult (With existing bed + 1 extra bed)&nbsp;</li><li>1 infant with Baby cot&nbsp;</li></ul><p>Note:&nbsp;Children below 12 years old <strong>are not recommended</strong> to stay at <strong>1BR Pool Villa and 2BR Pool Villa&nbsp;</strong></p>', 'Draft', '2024-05-13 03:20:19', '2025-04-02 01:02:57'),
(689, 93, '1748589031_4..jpg', '3BR Luxury Pool Villa Paddy View', 6, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drinks upon arrival.&nbsp;</li><li>Daily Breakfast served at Akar Restaurant from 07.00 - 11.00.&nbsp;</li><li>Water Dispenser with gallon.&nbsp;</li><li>Complimentary Coffee and Tea-making facilities in the villa.&nbsp;</li><li>Morning Walk Relaxation through scenic rice fields, led by the concierge team (scheduled).&nbsp;</li><li>Sunrise Yoga Sessions are based on the schedule (reservation required).&nbsp;</li><li>Access to Gym Facilities and Kabana Jungle Pool Club.&nbsp;</li><li>Shuttle Service to and from Ubud Centre.&nbsp;</li><li>24-Hour Butler Service</li></ul>', '<ul><li>Occupancy: 6 adults &amp; 1 child&nbsp;</li><li>Room Size: 400 sqm&nbsp;</li></ul>', 'Active', '2024-05-17 10:08:16', '2025-05-30 07:10:31'),
(690, 11, '1759977385_Panoramic Ocean View Villa.jpg', '1BR Panoramic Ocean Pool Villa', 2, 1, 'Panoramic Ocean View', 'King Bed', 403, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink upon arrival&nbsp;</li><li>Welcome amenities upon arrival in the villa for special occasion (birthday/anniversary/honeymooner/VIP) must be inform upon make a booking&nbsp;</li><li>Birthday amenities : birthday cake&nbsp;</li><li>Honeymoon : red yukata, red rose and swan art towel on the bathtub&nbsp;</li><li>Anniversary : red rose &amp; swan art towel on the bed&nbsp;</li><li>Bathroom amenities&nbsp;</li><li>Curator Service 24/7&nbsp;</li><li>6 bottles of mineral water per day, in-room coffee &amp; tea making facilities (1BR Pool Villa)&nbsp;</li><li>10 bottles of mineral water per day, in-room coffee &amp; tea making facilities (2BR Pool Villa)&nbsp;</li><li>24 bottles of mineral water per day, in-room coffee &amp; tea making facilities (3BR Pool Villa)&nbsp;</li><li>Daily breakfast Commune Restaurant&nbsp;</li><li>Complimentary Wi-Fi at resorts area&nbsp;</li><li>Complimentary access to Kids Club&nbsp;</li><li>Daily turndown Service with different souvenir</li><li>Complimentary shuttle service to Melasti Beach / UMA Beach house&nbsp;</li><li>Daily free yoga session at 07:30 A.M, in yoga pavilion</li></ul>', '<br>', 'Active', '2024-05-31 03:28:29', '2025-10-09 02:36:25'),
(691, 11, '1756691117_5..webp', '2BR Tropical Garden Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink upon arrival&nbsp;</li><li>Welcome amenities upon arrival in the villa for special occasion (birthday/anniversary/honeymooner/VIP) must be inform upon make a booking&nbsp;</li><li>Birthday amenities : birthday cake&nbsp;</li><li>Honeymoon : red yukata, red rose and swan art towel on the bathtub&nbsp;</li><li>Anniversary : red rose &amp; swan art towel on the bed&nbsp;</li><li>Bathroom amenities&nbsp;</li><li>Curator Service 24/7&nbsp;</li><li>6 bottles of mineral water per day, in-room coffee &amp; tea making facilities (1BR Pool Villa)&nbsp;</li><li>10 bottles of mineral water per day, in-room coffee &amp; tea making facilities (2BR Pool Villa)&nbsp;</li><li>24 bottles of mineral water per day, in-room coffee &amp; tea making facilities (3BR Pool Villa)&nbsp;</li><li>Daily breakfast Commune Restaurant&nbsp;</li><li>Complimentary Wi-Fi at resorts area&nbsp;</li><li>Complimentary access to Kids Club&nbsp;</li><li>Daily turndown Service with different souvenir</li><li>Complimentary shuttle service to Melasti Beach / UMA Beach house&nbsp;</li><li>Daily free yoga session at 07:30 A.M, in yoga pavilion</li></ul>', '<ul><li>Size:&nbsp;562 sq. m./6,049 sq. ft.</li></ul>', 'Active', '2024-05-31 03:29:20', '2025-09-01 01:45:17'),
