(720, 10, '1728264149_Classic Family.webp', 'Ayodya Resort - Classic Family', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink &amp; cold towel provided upon arrival.&nbsp;</li><li>Complimentary 24-hour access to the fitness center.&nbsp;</li><li>Complimentary access to all resort activities, kid’s activities at kid’s club and Balinese cultural activities at Bale Banjar.&nbsp;</li><li>Complimentary internet access available throughout the resort.&nbsp;</li><li>Inter-connecting room are available. Please request for connecting room in advance, subject to availability.</li></ul>', 'Room size: 48 sqm&nbsp;', 'Active', '2024-10-07 02:22:29', '2025-03-26 02:18:38'),
(721, 10, '1728264791_WhatsApp Image 2024-10-07 at 09.28.11.webp', 'Ayodya Resort - Family Interconnecting', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink &amp; cold towel provided upon arrival.&nbsp;</li><li>Complimentary 24-hour access to the fitness center.&nbsp;</li><li>Complimentary access to all resort activities, kid’s activities at kid’s club and Balinese cultural activities at Bale Banjar.&nbsp;</li><li>Complimentary internet access available throughout the resort.&nbsp;</li><li>Inter-connecting room are available. Please request for connecting room in advance, subject to availability.</li></ul>', 'Room size: 96 sqm&nbsp;', 'Active', '2024-10-07 02:33:11', '2025-03-26 02:19:31'),
(722, 10, '1728265864_WhatsApp Image 2024-10-07 at 09.46.54.webp', 'The Ayodya Palace - Suites Collections', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Ayodya Palace Lounge access from 07.00hrs till 00.00hrs&nbsp;</li><li>Choice of Buffet and A’ la carte breakfast served in Ayodya Palace Lounge, with Sparkling Wine from 7.00hrs - 11.00hrs&nbsp;</li><li>Afternoon tea served in Ayodya Palace Lounge from 15.00hrs - 16.30hrs&nbsp;</li><li>Evening cocktails and canapés from 18.00hrs - 19.30hrs&nbsp;</li><li>Complimentary laundry and pressing up to 4 (four) pieces per room per day&nbsp;</li><li>Access to Ayodya Palace Pool &amp; Loungers&nbsp;</li><li>Complimentary fruit, snacks, soft beverages, tea and coffee throughout the day at Ayodya Palace Lounge &amp; Pool&nbsp;</li><li>Selection of alcoholic and non-alcoholic beverages replenished daily in-room Mini Bar&nbsp;</li><li>Selection of tropical fruits replenished daily in the room&nbsp;</li><li>Personalized check-in / check-out at Palace Reception&nbsp;</li><li>Complimentary access to 24-hour Fitness Centre&nbsp;</li><li>Complimentary access to Camp Ananda Kids Club for children under 12 years old&nbsp;</li><li>Access to resort facilities and activities&nbsp;</li></ul>', 'Room size: Start 115 sqm&nbsp;', 'Active', '2024-10-07 02:51:04', '2025-03-26 02:21:43'),
(723, 124, '1737428407_1. Sanctoo Suites.jpg', 'Sanctoo Suites', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily breakfast for 2 persons</li><li>Free unlimited Bali Zoo access + visit to Kampung Sumatra, featuring an unforgettable animal encounter, mesmerizing bird show, and access to Jungle Splash</li><li>Welcome drink &amp; cool towel upon arrival&nbsp;</li><li>Complimentary 1x access to Flamingo Beach Club (Restaurant Indoor seating)</li><li>a 20-minute photo session by a professional photographer (includes 1 free soft-copy photo)</li><li>Enjoy the convenience of free shuttle service to Ubud Central, with drop-off at 9 AM and pick-up at 6 PM.</li></ul>', '<ul><li>Size: 50 sqm&nbsp;</li></ul>', 'Active', '2024-10-09 04:11:25', '2025-05-15 05:55:17'),
(724, 124, '1737439760_suite-pool-access-4-1024x682.jpg', 'Suites Pool Access', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily breakfast for 2 persons</li><li>Free unlimited Bali Zoo access + visit to Kampung Sumatra, featuring an unforgettable animal encounter, mesmerizing bird show, and access to Jungle Splash</li><li>Welcome drink &amp; cool towel upon arrival&nbsp;</li><li>Complimentary 1x access to Flamingo Beach Club (Restaurant Indoor seating)</li><li>a 20-minute photo session by a professional photographer (includes 1 free soft-copy photo)</li><li>Enjoy the convenience of free shuttle service to Ubud Central, with drop-off at 9 AM and pick-up at 6 PM.</li></ul>', '<ul><li>Size: 50 sqm&nbsp;</li></ul>', 'Active', '2024-10-09 04:18:13', '2025-05-15 05:55:38');
