(765, 6, '1734676050_WhatsApp Image 2024-12-20 at 14.24.52.jpeg', 'One Bedroom Uluwatu Pool Villa', 2, 1, 'Pool View', 'King Bed', 290, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily a la carte breakfast</li><li>Host (butler) service</li><li>Wi-Fi Internet access throughout the resort</li><li>Morning yoga session from 07.30 - 08.30 am</li><li>Use of 24-hour Gym</li><li>24-hour Library</li><li>Alila Living bath amenities</li><li>Complimentary drop off and pick up service to and from Savaya</li></ul>', NULL, 'Active', '2024-12-20 06:27:30', '2026-01-09 03:47:13'),
(766, 123, '1756188571_6..webp', 'Palace Club Lagoon Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<b>PALACE CLUB PRIVILEGES:</b><br><ul><li>Access to Palace Club Lounge open from 6.30 AM – 11 PM&nbsp;</li><li>Private check in and check out at the Palace Club Lounge&nbsp;</li><li>Late check out until 3:00 PM on day of departure&nbsp;</li><li>Welcome drink &amp; cold towel upon check in at Palace Club Lounge&nbsp;</li><li>Welcome fruits &amp; flowers upon arrival&nbsp;</li><li>Complimentary pressing service for 4 (four) garments on arrival day&nbsp;</li><li>Complimentary in room bottled water refreshed daily</li></ul><b>PALACE CLUB LOUNGE:</b><br><ul><li>Breakfast 6.30 AM – 11 AM&nbsp;</li><li>Afternoon Tea 3 PM – 5 PM&nbsp;</li><li>Evening Cocktail with assorted snacks 5.30 PM – 7 PM&nbsp;</li><li>Complimentary nonalcoholic beverages 11 AM – 11 PM&nbsp;</li><li>Computers &amp; printer&nbsp;</li><li>WIFI&nbsp;</li><li>Books collection (mini library) and DVD&nbsp;</li><li>Newspapers &amp; magazines&nbsp;</li><li>Complimentary access to the Sport Centre , Sauna, Steam room, Lap Pool and Jacuzzi&nbsp;</li></ul><b>ROOM BENEFIT:</b><br><ul><li>Honeymoon will receive honeymoon benefit upon arrival (honeymoon decoration on the bed, welcome tropical fruit and flower arrangement, glass dome chocolates and bathtub tray for room with bathtub).&nbsp;</li><li>Wedding anniversary will receive benefit on the wedding anniversary date (honeymoon decoration on the bed, glass dome chocolates, flower arrangement with card set up in the room, bathtub tray for room with bathtub).&nbsp;</li><li>Birthday benefit will receive benefit on the birthday date (chocolate petit cake with candle serve in the room or restaurant, flower arrangement with card set up on the dressing table in the room or restaurant table).&nbsp;</li><li>Wedding certificate should be presented during check in or upon reservation made.</li></ul>', '<ul><li>Room Size:&nbsp;56 m² / 602 sq ft</li></ul>', 'Draft', '2025-01-08 03:24:52', '2025-09-30 01:13:45'),
(767, 123, '1756188748_7. Palace Club Suite Room.jpg', 'Palace Club Suite Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<b>PALACE CLUB PRIVILEGES:</b><br><ul><li>Access to Palace Club Lounge open from 6.30 AM – 11 PM&nbsp;</li><li>Private check in and check out at the Palace Club Lounge&nbsp;</li><li>Late check out until 3:00 PM on day of departure&nbsp;</li><li>Welcome drink &amp; cold towel upon check in at Palace Club Lounge&nbsp;</li><li>Welcome fruits &amp; flowers upon arrival&nbsp;</li><li>Complimentary pressing service for 4 (four) garments on arrival day&nbsp;</li><li>Complimentary in room bottled water refreshed daily</li></ul><b>PALACE CLUB LOUNGE:</b><br><ul><li>Breakfast 6.30 AM – 11 AM&nbsp;</li><li>Afternoon Tea 3 PM – 5 PM&nbsp;</li><li>Evening Cocktail with assorted snacks 5.30 PM – 7 PM&nbsp;</li><li>Complimentary nonalcoholic beverages 11 AM – 11 PM&nbsp;</li><li>Computers &amp; printer&nbsp;</li><li>WIFI&nbsp;</li><li>Books collection (mini library) and DVD&nbsp;</li><li>Newspapers &amp; magazines&nbsp;</li><li>Complimentary access to the Sport Centre , Sauna, Steam room, Lap Pool and Jacuzzi&nbsp;</li></ul><b>ROOM BENEFIT:</b><br><ul><li>Honeymoon will receive honeymoon benefit upon arrival (honeymoon decoration on the bed, welcome tropical fruit and flower arrangement, glass dome chocolates and bathtub tray for room with bathtub).&nbsp;</li><li>Wedding anniversary will receive benefit on the wedding anniversary date (honeymoon decoration on the bed, glass dome chocolates, flower arrangement with card set up in the room, bathtub tray for room with bathtub).&nbsp;</li><li>Birthday benefit will receive benefit on the birthday date (chocolate petit cake with candle serve in the room or restaurant, flower arrangement with card set up on the dressing table in the room or restaurant table).&nbsp;</li><li>Wedding certificate should be presented during check in or upon reservation made.</li></ul>', '<ul><li>Room Size:&nbsp;80 m² / 861 sq