(818, 141, '1742455884_1. Wae Rana Suite, Resort View.jfif', 'Wae Rana Suite, Resort View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>24-hour daily breakfast for 2 people, 4 people for Two-Bedroom Villa and 6 people for The Mansion</li><li>Luxurious return airport transfer&nbsp;</li><li>Three types of local indigenous amenities upon arrival&nbsp;</li><li>Pressing service up to 2 pieces per person per day&nbsp;</li><li>24-hour Butler service&nbsp;</li><li>Minibar (non-alcoholic beverages), including sweet &amp; savory snacks per stay (daily for Villa category)&nbsp;</li><li>Daily turndown service with special amenities&nbsp;</li><li>In-room and resort-wide high-speed Wi-Fi internet access</li><li>Complimentary access to facilities such as Gym, Sauna, Kids Club and daily activities as per resort schedule \r\n(charges may apply for selected activities)&nbsp;</li><li>Complimentary in-house water sport activities such as Kayak, Stand-up paddle, snorkelling gear and water \r\nscooter&nbsp;</li><li>Return airport transfer&nbsp;&nbsp;</li></ul>', '<ul><li>Size: 69 sqm</li></ul>', 'Draft', '2025-03-20 07:31:24', '2025-06-30 01:06:26'),
