(890, 148, '1752630234_1br royal courtyard.jpg', '1BR Royal Courtyard Villa', 2, 1, 'Pool View', 'King Bed', 300, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily A’la carte breakfast served at any restaurants including in the villa and at any time.&nbsp;</li><li>24-hour Butler Services.&nbsp;</li><li>Complimentary Wi-Fi internet connection throughout the resort.&nbsp;</li><li>Samaya creative welcome arrival experience.</li></ul>', NULL, 'Active', '2025-07-16 01:43:54', '2026-01-19 08:14:30'),
(891, 148, '1752630311_1br pool villa.jpg', '1BR Pool Villa', 2, 1, 'Pool View', 'King Bed', 220, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily A’la carte breakfast served at any restaurants including in the villa and at any time.&nbsp;</li><li>24-hour Butler Services.&nbsp;</li><li>Complimentary Wi-Fi internet connection throughout the resort.&nbsp;</li><li>Samaya creative welcome arrival experience.</li></ul>', NULL, 'Active', '2025-07-16 01:45:11', '2026-01-19 08:13:58'),
(892, 86, '1753324030_11. The Reserve Master Suite.avif', 'The Reserve Master Suite', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<b>THE RESERVE (16+ Years Age and above)&nbsp;</b><div><ul><li>Exclusive access to THE RESERVE Area&nbsp;</li><li>Exclusive area for arrival and departure experience&nbsp;</li><li>Daily complimentary cocktails and canapes for adults only (alcoholic drinks for above 18 years old) *&nbsp;</li><li>Daily complimentary Afternoon Tea&nbsp;</li><li>Unlimited access to THE RESERVE beach cabana&nbsp;</li><li>Unlimited access to private pool area for THE RESERVE adult only&nbsp;</li><li>Exclusive Breakfast area for THE RESERVE guest for adults only *&nbsp;</li><li>Concierge service&nbsp;</li><li>One-time complimentary pressing of two items per guest per stay&nbsp;</li><li>In-room espresso machine.&nbsp;</li><li>24-hour luggage porter&nbsp;</li><li>Complimentary Internet and Wi-Fi access throughout the resort&nbsp;</li><li>Welcome drink served in the RESERVE lounge upon check in&nbsp;</li><li>In-room welcome amenities upon arrival&nbsp;</li><li>In-room Premium bath amenities&nbsp;</li><li>Daily turndown service&nbsp;</li><li>Preferential reservation in the a la carte restaurants by our concierge&nbsp;</li><li>Extend check-out time until 2:00 pm (subject to availability)&nbsp;</li><li>Complimentary still and sparkling water at beach and swimming pool areas during the day&nbsp;</li></ul><i>*&nbsp;Please note that some areas at the hotel are dedicated to adults only (above 16 years old)&nbsp;</i><br><i>* The benefits are subject to change without prior notice&nbsp;</i></div>', '<ul><li>Room Size: 80m2&nbsp;</li><li>Maximum of Room Occupancy: 4 adults&nbsp;</li></ul>', 'Draft', '2025-07-24 02:27:10', '2025-07-24 07:06:41'),
