(900, 93, '1754467540_2. Sensual Infinity Pool tent.webp', '1BR Sensual Infinity Pool Tent - For Adults Only', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drinks upon arrival.&nbsp;</li><li>Daily Breakfast served at Akar Restaurant from 07.00 - 11.00.&nbsp;</li><li>Water Dispenser with gallon.&nbsp;</li><li>Complimentary Coffee and Tea-making facilities in the villa.&nbsp;</li><li>Morning Walk Relaxation through scenic rice fields, led by the concierge team (scheduled).&nbsp;</li><li>Sunrise Yoga Sessions are based on the schedule (reservation required).&nbsp;</li><li>Access to Gym Facilities and Kabana Jungle Pool Club.&nbsp;</li><li>Shuttle Service to and from Ubud Centre.&nbsp;</li><li>24-Hour Butler Service</li></ul>', '<ul><li>Occupancy: 2 adults&nbsp;&nbsp;</li><li>Room Size: 140 sqm&nbsp;</li></ul>', 'Active', '2025-08-06 08:05:40', '2025-08-06 08:27:05'),
(901, 78, '1754981965_6. panoramic view 2br rooftop pool villa.webp', 'Panoramic View 2BR Rooftop Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily a la carte breakfast at de Daara eateries or Room Service</li><li>Welcome drink and cool towel upon arrival&nbsp;</li><li>Welcome fresh seasonal fruit basket in the room&nbsp;</li><li>Daily replenish mini bar in the room&nbsp;</li><li>Guest activities based on the schedule (yoga, making the offerings, and anothers sharing with another guest)&nbsp;</li><li>Special Guest Celebration (Honeymoon, Anniversary, Birthday) additional benefits available based on request : standard decoration on the bed and cake&nbsp;</li><li>Coffee, tea and 2 bottles of mineral water in the room&nbsp;</li><li>Daily turn down service&nbsp;</li><li>Daily shuttle service to Ubud Center based on schedule&nbsp;</li><li>Wi-Fi connection in all hotel areas&nbsp;</li></ul>', '<ul><li>Room Size: 170 sqm&nbsp;</li></ul>', 'Active', '2025-08-12 06:59:25', '2025-08-12 06:59:34'),
(902, 11, '1756691409_7..jpg', '2BR Ocean View Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink upon arrival&nbsp;</li><li>Welcome amenities upon arrival in the villa for special occasion (birthday/anniversary/honeymooner/VIP) must be inform upon make a booking&nbsp;</li><li>Birthday amenities : birthday cake&nbsp;</li><li>Honeymoon : red yukata, red rose and swan art towel on the bathtub&nbsp;</li><li>Anniversary : red rose &amp; swan art towel on the bed&nbsp;</li><li>Bathroom amenities&nbsp;</li><li>Curator Service 24/7&nbsp;</li><li>6 bottles of mineral water per day, in-room coffee &amp; tea making facilities (1BR Pool Villa)&nbsp;</li><li>10 bottles of mineral water per day, in-room coffee &amp; tea making facilities (2BR Pool Villa)&nbsp;</li><li>24 bottles of mineral water per day, in-room coffee &amp; tea making facilities (3BR Pool Villa)&nbsp;</li><li>Daily breakfast Commune Restaurant&nbsp;</li><li>Complimentary Wi-Fi at resorts area&nbsp;</li><li>Complimentary access to Kids Club&nbsp;</li><li>Daily turndown Service with different souvenir</li><li>Complimentary shuttle service to Melasti Beach / UMA Beach house&nbsp;</li><li>Daily free yoga session at 07:30 A.M, in yoga pavilion</li></ul>', '<ul><li>Size:&nbsp;562 sq. m./ 6,049 sq. ft.</li></ul>', 'Active', '2025-09-01 01:50:09', '2025-09-01 01:50:33'),
